    23			// Check for line comment start (-- outside of quotes)
    24			if (!in_single_quote && !in_double_quote && !in_line_comment && ch == '-' && i + 1 < sql.length() &&
    25			    sql[i + 1] == '-') {
    26				in_line_comment = true;
    27			}
    28	
    29			// End line comment on newline
    30			if (in_line_comment && (ch == '\n' || ch == '\r')) {
    31				in_line_comment = false;
    32			}
    33	
    34			// Handle quotes (only when not in a comment)
    35			if (!in_line_comment) {
    36				if (ch == '\'' && !in_double_quote && (i == 0 || sql[i - 1] != '\\')) {
    37					in_single_quote = !in_single_quote;
    38				} else if (ch == '"' && !in_single_quote && (i == 0 || sql[i - 1] != '\\')) {
    39					in_double_quote = !in_double_quote;
    40				}
    41			}
    42	
    43			current_statement += ch;
    44	
    45			// If we hit a semicolon outside of quotes and comments, it's end of statement
    46			if (ch == ';' && !in_single_quote && !in_double_quote && !in_line_comment) {
    47				// Trim whitespace
    48				size_t start = current_statement.find_first_not_of(" \t\n\r");
    49				if (start != string::npos) {
    50					statements.push_back(current_statement.substr(start));
    51				}
    52				current_statement.clear();
    53			}
    54		}
    55	
    56		// Don't forget the last statement if it doesn't end with semicolon
    57		size_t start = current_statement.find_first_not_of(" \t\n\r");
    58		if (start != string::npos) {
    59			statements.push_back(current_statement.substr(start));
    60		}
    61	
    62		return statements;
    63	}
