    66		// Ensure core_functions extension is loaded - needed for bitwise operators (&, |) used in SQL macros
    67		ExtensionHelper::TryAutoLoadExtension(loader.GetDatabaseInstance(), "core_functions");
    68	
    69		// Get a connection to execute SQL
    70		auto conn = make_uniq<Connection>(loader.GetDatabaseInstance());
    71	
    72		int total_statements = 0;
