    74	
    75		// Load embedded SQL macros (excluding chain methods which are loaded on demand)
    76		for (const auto &macro_pair : EMBEDDED_SQL_MACROS) {
    77			const string &filename = macro_pair.first;
    78			const string &sql_content = macro_pair.second;
