 56		// Don't forget the last statement if it doesn't end with semicolon
 57		size_t start = current_statement.find_first_not_of(" \t\n\r");
 58		if (start != string::npos) {
 59			statements.push_back(current_statement.substr(start));
 60		}
 61	
 62		return statements;
 63	}
