 65	void RegisterASTSQLMacros(ExtensionLoader &loader) {
 66		// Ensure core_functions extension is loaded - needed for bitwise operators (&, |) used in SQL macros
 67		ExtensionHelper::TryAutoLoadExtension(loader.GetDatabaseInstance(), "core_functions");
 68	
 69		// Get a connection to execute SQL
 70		auto conn = make_uniq<Connection>(loader.GetDatabaseInstance());
 71	
 72		int total_statements = 0;
 73		int successful_statements = 0;
 74	
 75		// Load embedded SQL macros (excluding chain methods which are loaded on demand)
 76		for (const auto &macro_pair : EMBEDDED_SQL_MACROS) {
 77			const string &filename = macro_pair.first;
 78			const string &sql_content = macro_pair.second;
 79	
 80			// Skip chain methods - these are loaded by duckdb_ast_register_short_names()
 81			if (filename == "02b_chain_methods.sql") {
 82				continue;
 83			}
 84	
 85			// Split the SQL content into individual statements
 86			auto statements = SplitSQLStatements(sql_content);
 87	
 88			for (size_t i = 0; i < statements.size(); i++) {
 89				const auto &statement = statements[i];
 90	
 91				// Skip empty statements or comments
 92				if (statement.empty() || statement.find_first_not_of(" \t\n\r") == string::npos) {
 93					continue;
 94				}
 95	
 96				total_statements++;
 97	
 98				auto result = conn->Query(statement);
 99				if (result->HasError()) {
100					// Throw error with context about which statement failed
101					throw InvalidInputException("Failed to register macro from %s (statement %d/%d):\n"
102					                            "Statement: %.200s...\n"
103					                            "Error: %s",
104					                            filename.c_str(), (int)(i + 1), (int)statements.size(), statement.c_str(),
105					                            result->GetError().c_str());
106				}
107				successful_statements++;
108			}
109		}
110	}
